  "ui.im.secretSaved": { "zh": "已保存（留空则不修改）", "en": "Saved (leave blank to keep)", "zh-TW": "已儲存（留空則不修改）", "ko": "저장됨(비워 두면 유지)", "ja": "保存済み（空欄なら変更しない）", "de": "Gespeichert (leer lassen, um beizubehalten)", "es": "Guardado (deja en blanco para mantener)", "fr": "Enregistré (laisser vide pour conserver)", "it": "Salvato (lascia vuoto per mantenere)", "da": "Gemt (lad stå tomt for at beholde)", "pl": "Zapisano (pozostaw puste, aby zachować)", "ru": "Сохранено (оставьте пустым, чтобы не менять)", "ar": "تم الحفظ (اتركه فارغًا للإبقاء عليه)", "no": "Lagret (la stå tomt for å beholde)", "pt-BR": "Salvo (deixe em branco para manter)", "th": "บันทึกแล้ว (เว้นว่างเพื่อคงไว้)", "tr": "Kaydedildi (korumak için boş bırakın)", "uk": "Збережено (залиште порожнім, щоб не змінювати)" },
